import{MICDecoder}from"./mic-decoder.min.js";self.onmessage=function(e){const t=e.data;if("decode-rgb-plane"===t.type){const{planeIndex:e,width:r,height:s}=t;try{const n=new Uint8Array(t.planeBlobBuffer),f=MICDecoder.decodeRGBPlane(n,r,s),o=f.buffer.slice(f.byteOffset,f.byteOffset+f.byteLength);self.postMessage({type:"plane-done",planeIndex:e,planeBuf:o,error:null},[o])}catch(t){self.postMessage({type:"plane-done",planeIndex:e,planeBuf:null,error:t.message})}return}if("decode-strip"!==t.type)return;const{stripIndex:r,width:s,stripHeight:n}=t;try{let e;e=t.fileBuffer?new Uint8Array(t.fileBuffer,t.fileOffset,t.fileLength):new Uint8Array(t.blobBuffer);const f=MICDecoder.decode(e,s,n);if(t.outBuffer){new Uint16Array(t.outBuffer,2*t.outOffset,s*n).set(f),self.postMessage({type:"strip-done",stripIndex:r,error:null})}else{const e=f.buffer.slice(0);self.postMessage({type:"strip-done",stripIndex:r,pixelBuffer:e,error:null},[e])}}catch(e){self.postMessage({type:"strip-done",stripIndex:r,error:e.message})}};